import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"中国人民抗日战争纪念馆","description":"","frontmatter":{},"headers":[],"relativePath":"history/anti-japanese-war.md","filePath":"history/anti-japanese-war.md","lastUpdated":null}'),o={name:"history/anti-japanese-war.md"};function n(i,t,h,d,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="中国人民抗日战争纪念馆" tabindex="-1">中国人民抗日战争纪念馆 <a class="header-anchor" href="#中国人民抗日战争纪念馆" aria-label="Permalink to &quot;中国人民抗日战争纪念馆&quot;">​</a></h1><blockquote><p>&quot;铭记历史，珍爱和平。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国人民抗日战争纪念馆位于北京市丰台区宛平城内，是全国唯一一座全面反映中国人民抗日战争历史的大型综合性专题纪念馆。纪念馆建于1987年，是为了纪念抗日战争全面爆发50周年而建。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁14号线郭庄子站转公交</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市丰台区卢沟桥宛平城内街101号</td></tr></tbody></table><h2 id="历史背景" tabindex="-1">历史背景 <a class="header-anchor" href="#历史背景" aria-label="Permalink to &quot;历史背景&quot;">​</a></h2><h3 id="建馆缘起" tabindex="-1">建馆缘起 <a class="header-anchor" href="#建馆缘起" aria-label="Permalink to &quot;建馆缘起&quot;">​</a></h3><p>1987年，正值七七事变爆发50周年，中国人民抗日战争纪念馆在宛平城内建成。选择宛平城作为馆址，是因为1937年7月7日的七七事变就发生在宛平城外的卢沟桥，标志着中国全面抗战的开始。</p><h3 id="纪念馆意义" tabindex="-1">纪念馆意义 <a class="header-anchor" href="#纪念馆意义" aria-label="Permalink to &quot;纪念馆意义&quot;">​</a></h3><p>纪念馆是全国爱国主义教育示范基地，也是国家级抗战纪念设施、遗址，承担着爱国主义教育和历史研究的重要使命。</p><h2 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h2><h3 id="基本陈列" tabindex="-1">基本陈列 <a class="header-anchor" href="#基本陈列" aria-label="Permalink to &quot;基本陈列&quot;">​</a></h3><p>纪念馆的基本陈列&quot;伟大胜利——纪念中国人民抗日战争暨世界反法西斯战争胜利大型主题展览&quot;，分为八个部分：</p><h4 id="第一部分-民族危机-救亡兴起" tabindex="-1">第一部分：民族危机，救亡兴起 <a class="header-anchor" href="#第一部分-民族危机-救亡兴起" aria-label="Permalink to &quot;第一部分：民族危机，救亡兴起&quot;">​</a></h4><p>展示1931年九一八事变后，日本侵华不断加深，中华民族面临亡国灭种的危机。中国共产党率先举起武装抗日的旗帜，号召全国民众起来抗日。</p><h4 id="第二部分-国共合作-共赴国难" tabindex="-1">第二部分：国共合作，共赴国难 <a class="header-anchor" href="#第二部分-国共合作-共赴国难" aria-label="Permalink to &quot;第二部分：国共合作，共赴国难&quot;">​</a></h4><p>展示1936年西安事变的和平解决，促进了以国共合作为基础的抗日民族统一战线的形成。</p><h4 id="第三部分-抗战灯塔-中流砥柱" tabindex="-1">第三部分：抗战灯塔，中流砥柱 <a class="header-anchor" href="#第三部分-抗战灯塔-中流砥柱" aria-label="Permalink to &quot;第三部分：抗战灯塔，中流砥柱&quot;">​</a></h4><p>展示中国共产党在全民族抗战中发挥的中流砥柱作用。中国共产党领导的八路军、新四军深入敌后，开辟敌后战场。</p><h4 id="第四部分-日军暴行-惨绝人寰" tabindex="-1">第四部分：日军暴行，惨绝人寰 <a class="header-anchor" href="#第四部分-日军暴行-惨绝人寰" aria-label="Permalink to &quot;第四部分：日军暴行，惨绝人寰&quot;">​</a></h4><p>展示日军在中国犯下的滔天罪行：南京大屠杀、细菌战、化学战、强征慰安妇等。</p><h4 id="第五部分-浴血疆场-民族壮歌" tabindex="-1">第五部分：浴血疆场，民族壮歌 <a class="header-anchor" href="#第五部分-浴血疆场-民族壮歌" aria-label="Permalink to &quot;第五部分：浴血疆场，民族壮歌&quot;">​</a></h4><p>展示正面战场和敌后战场的英勇抗战。淞沪会战、太原会战、徐州会战、武汉会战等重大战役。</p><h4 id="第六部分-得道多助-国际支援" tabindex="-1">第六部分：得道多助，国际支援 <a class="header-anchor" href="#第六部分-得道多助-国际支援" aria-label="Permalink to &quot;第六部分：得道多助，国际支援&quot;">​</a></h4><p>展示国际反法西斯力量对中国的支援，以及中国对世界反法西斯战争的贡献。</p><h4 id="第七部分-历史胜利-巨大贡献" tabindex="-1">第七部分：历史胜利，巨大贡献 <a class="header-anchor" href="#第七部分-历史胜利-巨大贡献" aria-label="Permalink to &quot;第七部分：历史胜利，巨大贡献&quot;">​</a></h4><p>展示1945年抗日战争的胜利，以及中国抗战对世界反法西斯战争的巨大贡献。</p><h4 id="第八部分-以史为鉴-面向未来" tabindex="-1">第八部分：以史为鉴，面向未来 <a class="header-anchor" href="#第八部分-以史为鉴-面向未来" aria-label="Permalink to &quot;第八部分：以史为鉴，面向未来&quot;">​</a></h4><p>展示战后审判、中日关系等，告诫人们铭记历史、珍爱和平。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>七七事变日军炮弹</strong></td><td style="text-align:left;">卢沟桥事变时日军发射的炮弹</td></tr><tr><td style="text-align:left;"><strong>左权将军望远镜</strong></td><td style="text-align:left;">八路军副总参谋长左权使用</td></tr><tr><td style="text-align:left;"><strong>赵一曼遗书</strong></td><td style="text-align:left;">抗日女英雄赵一曼写给儿子的遗书</td></tr><tr><td style="text-align:left;"><strong>平型关大捷缴获的日军装备</strong></td><td style="text-align:left;">八路军首次大捷的战利品</td></tr><tr><td style="text-align:left;"><strong>地道战、地雷战实物</strong></td><td style="text-align:left;">敌后抗战的生动见证</td></tr></tbody></table><h2 id="纪念设施" tabindex="-1">纪念设施 <a class="header-anchor" href="#纪念设施" aria-label="Permalink to &quot;纪念设施&quot;">​</a></h2><h3 id="抗战胜利纪念墙" tabindex="-1">抗战胜利纪念墙 <a class="header-anchor" href="#抗战胜利纪念墙" aria-label="Permalink to &quot;抗战胜利纪念墙&quot;">​</a></h3><p>纪念馆广场上的抗战胜利纪念墙，正面镌刻着&quot;中国人民抗日战争纪念馆&quot;馆名，背面镌刻着&quot;铭记历史、缅怀先烈、珍爱和平、开创未来&quot;。</p><h3 id="独立自由勋章雕塑" tabindex="-1">独立自由勋章雕塑 <a class="header-anchor" href="#独立自由勋章雕塑" aria-label="Permalink to &quot;独立自由勋章雕塑&quot;">​</a></h3><p>广场中央矗立着独立自由勋章雕塑，高15米，象征着中国人民抗日战争的伟大胜利。</p><h3 id="铜质卧碑" tabindex="-1">铜质卧碑 <a class="header-anchor" href="#铜质卧碑" aria-label="Permalink to &quot;铜质卧碑&quot;">​</a></h3><p>卧碑上刻有&quot;中国人民抗日战争全面爆发纪念地&quot;字样。</p><h2 id="宛平城" tabindex="-1">宛平城 <a class="header-anchor" href="#宛平城" aria-label="Permalink to &quot;宛平城&quot;">​</a></h2><p>宛平城建于明崇祯十一年（1638年），是拱卫京师的军事要塞。1937年7月7日，七七事变在宛平城爆发，宛平城成为中国全面抗战的起点。</p><h3 id="古城风貌" tabindex="-1">古城风貌 <a class="header-anchor" href="#古城风貌" aria-label="Permalink to &quot;古城风貌&quot;">​</a></h3><p>宛平城保存较为完整，城墙、城门、城内街道基本保持原貌。城内有多处抗战遗址。</p><h3 id="弹痕墙" tabindex="-1">弹痕墙 <a class="header-anchor" href="#弹痕墙" aria-label="Permalink to &quot;弹痕墙&quot;">​</a></h3><p>宛平城墙上至今保留着当年的弹痕，是日军侵华的铁证。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>纪念馆参观（约2-3小时）</strong>：</p><p>抗战胜利纪念墙 → 独立自由勋章雕塑 → 纪念馆入口 → 序厅 → 第一部分至第八部分 → 珍贵文物展 → 宛平城城墙 → 弹痕墙 → 卢沟桥</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;">地铁+公交</td><td style="text-align:left;">14号线郭庄子站 → 309路/624路 → 宛平城</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">西四环 → 宛平城</td></tr><tr><td style="text-align:left;">旅游专线</td><td style="text-align:left;">部分旅行社有专线</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：纪念馆免费，但需提前预约</li><li><strong>庄重参观</strong>：怀着崇敬之心参观，保持肃静</li><li><strong>讲解服务</strong>：可租借语音导览或请人工讲解</li><li><strong>结合游览</strong>：建议与卢沟桥一起游览</li><li><strong>教育意义</strong>：适合带孩子进行爱国主义教育</li></ol><h2 id="教育意义" tabindex="-1">教育意义 <a class="header-anchor" href="#教育意义" aria-label="Permalink to &quot;教育意义&quot;">​</a></h2><p>纪念馆是全国爱国主义教育示范基地，每年接待数百万观众。参观纪念馆，可以让人们：</p><ul><li>铭记历史，勿忘国耻</li><li>缅怀先烈，珍惜和平</li><li>振奋精神，开创未来</li></ul><p>正如习近平总书记所说：</p><blockquote><p>&quot;一个有希望的民族不能没有英雄，一个有前途的国家不能没有先锋。&quot;</p></blockquote><hr><p><strong>📍 地址</strong>：北京市丰台区卢沟桥宛平城内街101号 <strong>📞 电话</strong>：010-83892355 <strong>🌐 官网</strong>：<a href="http://www.1937china.com" target="_blank" rel="noreferrer">www.1937china.com</a><strong>📱 预约</strong>：关注&quot;中国人民抗日战争纪念馆&quot;微信公众号预约</p>',60)])])}const g=a(o,[["render",n]]);export{b as __pageData,g as default};
